import React, {PureComponent} from 'react'
import CommentList from '../comment-list'
import PropTypes from 'prop-types'
import './style.css'
import {connect} from 'react-redux'
import {deleteArticle, loadArticle} from '../../actions'

class Article extends PureComponent {
    componentDidUpdate(prevProps, prevState, snapshot) {
        const {isOpen, loadArticle, article} = this.props
        if (!prevProps.isOpen && isOpen) {
            loadArticle(article.id)
        }
    }

    render() {
        const {article, isOpen} = this.props
        return (
            <div className="card mx-auto" style={{width: '75%'}}>
                <div className="card-header d-flex justify-content-between">
                    <h5>{article.title}</h5>
                    <div>
                        <button
                            onClick={this.toggleOpen}
                            className="btn btn-primary btn-sm"
                        >
                            {isOpen ? 'close' : 'open'}
                        </button>
                        <button
                            onClick={this.handleDelete}
                            className="btn btn-danger btn-sm ml-1"
                        >delete
                        </button>
                    </div>
                </div>
                <div className="card-body">
                    <h6 className="card-subtitle text-muted">creation
                        date: {(new Date(article.date)).toDateString()}</h6>
                        {this.body}
                </div>
            </div>
        )
    }

    get body() {
        const {article, isOpen} = this.props
        if (!isOpen) return null
        return (
            <section>
                <p className="card-text">{article.text}</p>
                <CommentList article={article} />
            </section>
        )
    }

    handleDelete = () => {
        this.props.deleteArticle(this.props.article.id)
    }

    toggleOpen = () => {
        this.props.toggleArticle(this.props.article.id)
    }
}

Article.propTypes = {
    isOpen: PropTypes.bool,
    toggleArticle: PropTypes.func,
    article: PropTypes.shape({
        id: PropTypes.string,
        title: PropTypes.string,
        text: PropTypes.string,
        comments: PropTypes.array
    })
}

const mapDispatchToProps = dispatch => ({
    deleteArticle: (id) => dispatch(deleteArticle(id)),
    loadArticle: (id) => dispatch(loadArticle(id))
})

export default connect(null, mapDispatchToProps)(Article)
